import React, { useState, useEffect } from 'react';
import './Registration.css';

function Register() {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    service: 'Web Development',
    paymentMethod: 'Online', // Default selected
    transactionId: '',
    message: ''
  });

  const [price, setPrice] = useState(0);

  useEffect(() => {
    const prices = {
      'Web Development': 5000,
      'UI/UX Design': 3000,
      'App Development': 8000,
      'Assignment Support': 500,
      'PPT Design': 300,
      'Report Writing': 400
    };
    setPrice(prices[formData.service]);
  }, [formData.service]);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log("Form Submitted:", formData);
    alert(`Registration Successful for ${formData.service}! Payment Mode: ${formData.paymentMethod}`);
  };

  return (
    <div className="register-page bg-light py-5">
      <div className="container">
        <div className="row justify-content-center">
          <div className="col-md-6">
            <div className="card shadow border-0 p-4 rounded-4">
              <div className="card-body">
                <h3 className="fw-bold text-center mb-4">Service Registration</h3>
                
                <form onSubmit={handleSubmit}>
                  {/* Name & Email */}
                  <div className="mb-3">
                    <label className="form-label fw-bold small">Full Name</label>
                    <input type="text" name="name" className="form-control" placeholder="Enter your name" required onChange={handleChange} />
                  </div>

                  <div className="mb-3">
                    <label className="form-label fw-bold small">Email Address</label>
                    <input type="email" name="email" className="form-control" placeholder="example@mail.com" required onChange={handleChange} />
                  </div>

                  <div className="mb-3">
                    <label className="form-label fw-bold small">Select Service</label>
                    <select name="service" className="form-select" onChange={handleChange} value={formData.service}>
                      <option value="Web Development">Web Development</option>
                      <option value="UI/UX Design">UI/UX Design</option>
                      <option value="App Development">App Development</option>
                      <option value="Assignment Support">Assignment Support</option>
                      <option value="PPT Design">PPT Design</option>
                      <option value="Report Writing">Report Writing</option>
                    </select>
                  </div>

                  {/* Payment Method Section */}
                  <div className="mt-4 p-3 border rounded bg-white shadow-sm">
                    <div className="d-flex justify-content-between align-items-center mb-3">
                      <h6 className="fw-bold m-0">Service Cost:</h6>
                      <span className="text-primary fw-bold fs-5">₹{price}</span>
                    </div>

                    <label className="form-label fw-bold small mb-2">Choose Payment Method</label>
                    <div className="d-flex gap-3 mb-3">
                      <div className="form-check p-2 flex-fill border rounded text-center">
                        <input className="form-check-input ms-0 me-2" type="radio" name="paymentMethod" id="online" value="Online" checked={formData.paymentMethod === 'Online'} onChange={handleChange} />
                        <label className="form-check-label small" htmlFor="online">Online Payment</label>
                      </div>
                      <div className="form-check p-2 flex-fill border rounded text-center">
                        <input className="form-check-input ms-0 me-2" type="radio" name="paymentMethod" id="cash" value="Cash" checked={formData.paymentMethod === 'Cash'} onChange={handleChange} />
                        <label className="form-check-label small" htmlFor="cash">Cash Payment</label>
                      </div>
                    </div>

                    {/* Conditional Transaction ID Input */}
                    {formData.paymentMethod === 'Online' && (
                      <div className="animate-fade">
                        <label className="form-label small fw-bold text-danger">Transaction ID / Ref No. *</label>
                        <input 
                          type="text" 
                          name="transactionId" 
                          className="form-control form-control-sm" 
                          placeholder="Enter Transaction ID" 
                          required={formData.paymentMethod === 'Online'} 
                          onChange={handleChange} 
                        />
                      </div>
                    )}
                  </div>

                  <button type="submit" className="btn btn-primary w-100 fw-bold py-2 mt-4 shadow">
                    Register Now
                  </button>
                </form>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default Register;
